module top_module(
  input [31:0] obf_in,
  input [1:0] shift,
  output reg [31:0] out
);always @(*)
  begin
    case(shift)
      2'b00: out = obf_in;
      2'b01: out = {obf_in[30:0], 1'b0};
      2'b10: out = {1'b0, obf_in[31:1]};
      2'b11: out = {2'b00, obf_in[31:2]};
    endcase
  end

endmodule
